// ── Helper ────────────────────────────────────────────────────────────────
// Returns the student-facing task for the selected (level, theme, phase,
// activityIdx). Returns '' if anything is missing so the UI can render an
// empty state gracefully. In dev, logs a warning to flag coverage gaps.
export function getHandout(level, theme, phaseId, activityIdx) {
  if (!level || !theme || !phaseId) return '';
  const phaseArr = HANDOUTS[level]?.[theme]?.[phaseId];
  if (!phaseArr) {
    if (import.meta.env?.DEV) {
      console.warn(`[handouts] missing cell: ${level}/${theme}/${phaseId}/${activityIdx}`);
    }
    return '';
  }
  const cell = phaseArr[activityIdx ?? 0];
  if (cell === undefined && import.meta.env?.DEV) {
    console.warn(`[handouts] missing activity: ${level}/${theme}/${phaseId}/${activityIdx}`);
  }
  return cell || '';
}
